const items = $input.all();
const companies = [];
const seen = new Set();

for (const item of items) {
  const body = item.json;
  let repos = [];

  if (body.items && Array.isArray(body.items)) {
    repos = body.items;
  } else if (Array.isArray(body)) {
    repos = body;
  }

  for (const repo of repos) {
    const owner = repo.owner;
    if (!owner || owner.type !== 'Organization') continue;

    const orgName = owner.login;
    if (seen.has(orgName)) continue;
    seen.add(orgName);

    const repoUrl = repo.html_url || 'Unknown';
    const orgUrl = `https://github.com/${orgName}`;
    const topics = repo.topics ? repo.topics.join(', ') : 'Unknown';
    const language = repo.language || 'Unknown';

    companies.push({
      json: {
        Company: orgName,
        Website: orgUrl,
        Careers_URL: 'Unknown',
        Country: 'Unknown',
        City: 'Unknown',
        Sector: 'Technology',
        Subsector: 'Data / AI',
        Company_Stage: 'Unknown',
        Company_Scale: 'Unknown',
        Employer_Category: 'GitHub Signal',
        Remote: 'Unknown',
        Visa_Sponsorship: 'Unknown',
        EOR: 'Unknown',
        Hiring_Geography: 'Unknown',
        Target_Roles: 'Data Engineer, AI/ML Engineer',
        Tech_Stack: language + (topics !== 'Unknown' ? ', ' + topics : ''),
        Region_Eligibility: 'Unknown',
        Portfolio_Theme_Match: 'Yes - RAG/DBT Stack',
        Language_Requirement: 'English',
        Hiring_Confidence: 'Low',
        Reason_Match: `Active GitHub org using RAG/DBT stack (repo: ${repoUrl})`,
        Source: 'GitHub API Stack Signal',
        Cold_Outreach_Candidate: 'Yes',
        Visa_Sponsor_Register: 'Unknown'
      }
    });
  }
}

if (companies.length === 0) {
  return [{ json: { message: 'No organizations found', note: 'All repos may be from individual users' } }];
}

return companies;
